  if (!newOwnerRow) throw new NotFoundError("找不到新 Owner 成員");
  setMemberFields(newOwnerRow, tenantId, tenant, newOwnerUid, "owner");
  try { twsSave(newOwnerRow); } catch (errProm) { throw new BadRequestError("更新新 Owner 角色失敗"); }
